#!/usr/bin/env python
# -*- coding: utf-8 -*-
"""
v22_lite_notebook - standalone end-to-end builder for the final V22-lite submission

This single file vendors the original source of:
  - suho/v17.py
  - suho/v19.py
  - suho/v21_expert.py
  - yysop/src/xgb_kfold_v2.py
  - yysop/src/lightgbm_kfold_v1.py
  - v22-lite inner notebook

What it does:
  1. materializes the vendored team scripts into a temporary workspace
  2. copies raw data (train/test/sample_submission) into each expected location
  3. runs v17 and v19 to recreate the external global blend npy
  4. runs XGB/LGB branch trainers
  5. runs the final v22-lite CatBoost expert pipeline
  6. rebuilds the final 3-model rank ensemble submission (xgb=0.16/lgb=0.04/cat=0.80)

Notes:
  - v21_expert.py is materialized as part of the lineage/reference set, but is not required
    for the final v22-lite execution path unless --run-v21-reference is explicitly passed.
  - This file is standalone as code, but still requires raw competition data files:
    train.csv, test.csv, sample_submission.csv
"""

from __future__ import annotations

import argparse
import base64
import gzip
import json
import shutil
import subprocess
import sys
import tempfile
from pathlib import Path

import numpy as np
import pandas as pd
from sklearn.metrics import roc_auc_score


EMBEDDED_SOURCES = {
    "suho/v17.py": "",
    "suho/v19.py": "",
    "suho/v21_expert.py": "",
    "yysop/src/xgb_kfold_v2.py": "",
    "yysop/src/lightgbm_kfold_v1.py": "",
    "v22_lite/inner_v22_lite_notebook.py": ""
}

TRIO_WEIGHTS = {
    "xgb": 0.16,
    "lgb": 0.04,
    "cat": 0.80,
}


def decode_source(encoded: str) -> str:
    return gzip.decompress(base64.b64decode(encoded)).decode("utf-8")


def write_text(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")


def materialize_sources(work_dir: Path) -> None:
    for rel_path, encoded in EMBEDDED_SOURCES.items():
        write_text(work_dir / rel_path, decode_source(encoded))


def copy_required_data(data_dir: Path, work_dir: Path) -> None:
    required = ["train.csv", "test.csv", "sample_submission.csv"]
    missing = [name for name in required if not (data_dir / name).exists()]
    if missing:
        raise FileNotFoundError(
            f"Missing required data files in {data_dir}: {', '.join(missing)}"
        )

    targets = [
        work_dir / "data",
        work_dir / "yysop" / "data",
        work_dir / "v22_lite" / "data",
    ]
    for target_dir in targets:
        target_dir.mkdir(parents=True, exist_ok=True)
        for name in required:
            shutil.copy2(data_dir / name, target_dir / name)


def run_script(python_exe: str, script_path: Path, cwd: Path) -> None:
    cmd = [python_exe, str(script_path)]
    print(f"[RUN] {' '.join(cmd)} (cwd={cwd})")
    subprocess.run(cmd, cwd=str(cwd), check=True)


def maybe_run_v21_reference(python_exe: str, work_dir: Path) -> None:
    run_script(
        python_exe,
        work_dir / "suho" / "v21_expert.py",
        work_dir / "suho",
    )


def copy_global_blend_outputs(work_dir: Path) -> None:
    suho_result = work_dir / "suho" / "result"
    target_npy = work_dir / "v22_lite" / "npy"
    target_npy.mkdir(parents=True, exist_ok=True)

    for name in [
        "oof_v17_final.npy",
        "test_v17_final.npy",
        "oof_v19_final.npy",
        "test_v19_final.npy",
    ]:
        src = suho_result / name
        if not src.exists():
            raise FileNotFoundError(f"Expected global blend artifact not found: {src}")
        shutil.copy2(src, target_npy / name)


def find_target_column(df: pd.DataFrame) -> str:
    for candidate in ("임신 성공 여부", "target"):
        if candidate in df.columns:
            return candidate
    excluded = {"ID", "oof_pred_prob", "oof_pred_label", "correct", "probability"}
    candidates = [c for c in df.columns if c not in excluded]
    if len(candidates) == 1:
        return candidates[0]
    if len(df.columns) >= 2:
        return df.columns[1]
    raise ValueError("Could not infer target column.")


def find_oof_prediction_column(df: pd.DataFrame) -> str:
    for candidate in ("oof_pred_prob", "probability", "pred", "prediction"):
        if candidate in df.columns:
            return candidate

    excluded = {"ID", "oof_pred_label", "correct", find_target_column(df)}
    candidates = [c for c in df.columns if c not in excluded]
    if candidates:
        return candidates[-1]
    raise ValueError("Could not infer OOF prediction column.")


def find_submission_prediction_column(df: pd.DataFrame) -> str:
    for candidate in ("probability", "임신 성공 여부", "target"):
        if candidate in df.columns and candidate != "ID":
            return candidate
    candidates = [c for c in df.columns if c != "ID"]
    if candidates:
        return candidates[-1]
    raise ValueError("Could not infer submission prediction column.")


def load_oof_csv(path: Path) -> tuple[np.ndarray, np.ndarray]:
    df = pd.read_csv(path)
    target_col = find_target_column(df)
    pred_col = find_oof_prediction_column(df)
    return df[target_col].to_numpy(), df[pred_col].to_numpy()


def load_submission_csv(path: Path) -> tuple[np.ndarray, np.ndarray]:
    df = pd.read_csv(path)
    if "ID" not in df.columns:
        raise ValueError(f"ID column not found in {path}")
    pred_col = find_submission_prediction_column(df)
    return df["ID"].to_numpy(), df[pred_col].to_numpy()


def to_rank(values: np.ndarray) -> np.ndarray:
    return pd.Series(values).rank(method="average", pct=True).to_numpy()


def build_rank_ensemble(work_dir: Path, output_dir: Path) -> Path:
    y_xgb, xgb_oof = load_oof_csv(
        work_dir / "yysop" / "outputs" / "xgb_v2_reg_relax_oof_predictions.csv"
    )
    y_lgb, lgb_oof = load_oof_csv(
        work_dir
        / "yysop"
        / "outputs"
        / "lightgbm_v1_lightgbm_baseline_v1_oof_predictions.csv"
    )
    cat_oof = np.load(
        work_dir / "v22_lite" / "result_v22_lite" / "oof_v22_lite_final.npy"
    )

    if not np.array_equal(y_xgb, y_lgb):
        raise ValueError("XGB and LGB target arrays do not match.")
    if len(cat_oof) != len(y_xgb):
        raise ValueError(
            f"CatBoost OOF length mismatch: {len(cat_oof)} vs {len(y_xgb)}"
        )

    xgb_ids, xgb_sub = load_submission_csv(
        work_dir / "yysop" / "outputs" / "xgb_v2_reg_relax_submission.csv"
    )
    lgb_ids, lgb_sub = load_submission_csv(
        work_dir
        / "yysop"
        / "outputs"
        / "lightgbm_v1_lightgbm_baseline_v1_submission.csv"
    )
    cat_test = np.load(
        work_dir / "v22_lite" / "result_v22_lite" / "test_v22_lite_final.npy"
    )
    sample_sub = pd.read_csv(work_dir / "data" / "sample_submission.csv")

    if not np.array_equal(xgb_ids, lgb_ids):
        raise ValueError("XGB and LGB submission IDs do not match.")
    if len(cat_test) != len(xgb_sub):
        raise ValueError(
            f"CatBoost test length mismatch: {len(cat_test)} vs {len(xgb_sub)}"
        )
    if len(sample_sub) != len(xgb_sub):
        raise ValueError(
            f"Sample submission length mismatch: {len(sample_sub)} vs {len(xgb_sub)}"
        )

    oof_pred = (
        TRIO_WEIGHTS["xgb"] * to_rank(xgb_oof)
        + TRIO_WEIGHTS["lgb"] * to_rank(lgb_oof)
        + TRIO_WEIGHTS["cat"] * to_rank(cat_oof)
    )
    oof_auc = roc_auc_score(y_xgb, oof_pred)

    test_pred = (
        TRIO_WEIGHTS["xgb"] * to_rank(xgb_sub)
        + TRIO_WEIGHTS["lgb"] * to_rank(lgb_sub)
        + TRIO_WEIGHTS["cat"] * to_rank(cat_test)
    )

    output_dir.mkdir(parents=True, exist_ok=True)
    submission = sample_sub.copy()
    submission["probability"] = test_pred
    out_csv = output_dir / "rank_ensemble_v22_lite_2seed_champ_weight.csv"
    submission.to_csv(out_csv, index=False)

    oof_df = pd.DataFrame(
        {
            "ID": pd.read_csv(work_dir / "data" / "train.csv")["ID"],
            "임신 성공 여부": y_xgb,
            "rank_ensemble_pred": oof_pred,
        }
    )
    oof_df.to_csv(
        output_dir / "rank_ensemble_v22_lite_2seed_champ_weight_oof.csv",
        index=False,
        encoding="utf-8-sig",
    )

    summary = {
        "weights": TRIO_WEIGHTS,
        "oof_auc": float(oof_auc),
        "xgb_oof_path": str(work_dir / "yysop" / "outputs" / "xgb_v2_reg_relax_oof_predictions.csv"),
        "lgb_oof_path": str(work_dir / "yysop" / "outputs" / "lightgbm_v1_lightgbm_baseline_v1_oof_predictions.csv"),
        "cat_oof_path": str(work_dir / "v22_lite" / "result_v22_lite" / "oof_v22_lite_final.npy"),
        "submission_path": str(out_csv),
    }
    with open(output_dir / "standalone_summary.json", "w", encoding="utf-8") as f:
        json.dump(summary, f, ensure_ascii=False, indent=2)

    print("=== Final Rank Ensemble Completed ===")
    print(f"OOF AUC: {oof_auc:.6f}")
    print(f"Saved: {out_csv}")
    return out_csv


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Standalone end-to-end builder for the final v22-lite submission."
    )
    parser.add_argument(
        "--data-dir",
        type=Path,
        default=Path(__file__).resolve().parent / "data",
        help="Directory containing train.csv, test.csv, sample_submission.csv",
    )
    parser.add_argument(
        "--output-dir",
        type=Path,
        default=Path(__file__).resolve().parent / "standalone_output",
        help="Directory to store the rebuilt final submission and summaries",
    )
    parser.add_argument(
        "--work-dir",
        type=Path,
        default=None,
        help="Optional working directory. If omitted, a temp directory is used.",
    )
    parser.add_argument(
        "--python-exe",
        type=str,
        default=sys.executable,
        help="Python executable for child scripts",
    )
    parser.add_argument(
        "--prepare-only",
        action="store_true",
        help="Only materialize sources and copy data; do not run training scripts.",
    )
    parser.add_argument(
        "--keep-workdir",
        action="store_true",
        help="Keep the temporary working directory after completion.",
    )
    parser.add_argument(
        "--run-v21-reference",
        action="store_true",
        help="Also execute vendored v21_expert.py for reference outputs.",
    )
    return parser.parse_args()


def main() -> None:
    args = parse_args()

    work_dir = args.work_dir
    temp_created = False
    if work_dir is None:
        work_dir = Path(tempfile.mkdtemp(prefix="v22_lite_standalone_"))
        temp_created = True
    else:
        work_dir.mkdir(parents=True, exist_ok=True)

    print(f"[INFO] work_dir={work_dir}")
    print(f"[INFO] data_dir={args.data_dir}")
    print(f"[INFO] output_dir={args.output_dir}")

    try:
        materialize_sources(work_dir)
        copy_required_data(args.data_dir, work_dir)

        if args.prepare_only:
            print("[INFO] prepare-only complete")
            return

        run_script(args.python_exe, work_dir / "suho" / "v17.py", work_dir / "suho")
        run_script(args.python_exe, work_dir / "suho" / "v19.py", work_dir / "suho")

        if args.run_v21_reference:
            maybe_run_v21_reference(args.python_exe, work_dir)

        copy_global_blend_outputs(work_dir)

        run_script(
            args.python_exe,
            work_dir / "yysop" / "src" / "xgb_kfold_v2.py",
            work_dir / "yysop" / "src",
        )
        run_script(
            args.python_exe,
            work_dir / "yysop" / "src" / "lightgbm_kfold_v1.py",
            work_dir / "yysop" / "src",
        )
        run_script(
            args.python_exe,
            work_dir / "v22_lite" / "inner_v22_lite_notebook.py",
            work_dir / "v22_lite",
        )

        build_rank_ensemble(work_dir, args.output_dir)
    finally:
        if temp_created and not args.keep_workdir:
            shutil.rmtree(work_dir, ignore_errors=True)


if __name__ == "__main__":
    main()
